import logo from '../Assets/home.png'
import React from 'react';
import { Link } from 'react-router-dom';

function Header() {

    return (
        <header className="App-header">
            <div className="left-Header">
            <Link className="path" id="Home" to="/"><b>Name</b></Link>
                <Link className="path" id="image" to="/"><img src={logo} alt="toMainMenu" /></Link>
                <Link className="path" id="AboutUs" to="/about">เกี่ยวกับเรา</Link>
            </div>
            <div className="Right-header">
                <button id="Login" className="headerButton" onClick={handleLoginClick}>Log In</button>
                <button id="signup" className="headerButton" onClick={handleSignupClick}>Join Now</button>
            </div>
        </header>
    )
}

export default Header;
